import{_ as s,o as a,c as t,ae as n}from"./chunks/framework.D0EcU_Ug.js";const u=JSON.parse('{"title":"Windows OpenSSH 服务器免密登录","description":"","frontmatter":{},"headers":[],"relativePath":"notes/interop/windows-ssh-server-key-auth.md","filePath":"notes/interop/windows-ssh-server-key-auth.md"}'),i={name:"notes/interop/windows-ssh-server-key-auth.md"};function o(p,e,r,d,l,h){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="windows-openssh-服务器免密登录" tabindex="-1">Windows OpenSSH 服务器免密登录 <a class="header-anchor" href="#windows-openssh-服务器免密登录" aria-label="Permalink to &quot;Windows OpenSSH 服务器免密登录&quot;">​</a></h1><p>这个坑很典型：前面的公钥配置明明都按 Linux 那套做完了，但连 Windows 的 OpenSSH 服务器时还是继续要密码。</p><h2 id="原因" tabindex="-1">原因 <a class="header-anchor" href="#原因" aria-label="Permalink to &quot;原因&quot;">​</a></h2><p>Windows 的 OpenSSH 默认会对管理员组走另一套 <code>AuthorizedKeysFile</code> 路径。</p><h2 id="解决方法" tabindex="-1">解决方法 <a class="header-anchor" href="#解决方法" aria-label="Permalink to &quot;解决方法&quot;">​</a></h2><p>打开：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:\\ProgramData\\ssh\\sshd_config</span></span></code></pre></div><p>把下面两行注释掉：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Match Group administrators</span></span>
<span class="line"><span>       AuthorizedKeysFile __PROGRAMDATA__/ssh/administrators_authorized_keys</span></span></code></pre></div><p>然后去 Windows 的“服务”里重启：</p><ul><li><code>OpenSSH SSH Server</code></li></ul><p>做完这一步，免密登录基本就正常了。</p>`,12)])])}const _=s(i,[["render",o]]);export{u as __pageData,_ as default};
